import os
import sys
import subprocess


def run(cmd):
    print("+", " ".join(cmd), flush=True)
    subprocess.check_call(cmd)


def main():
    requirements_file = os.environ.get("REQUIREMENTS_FILE", "requirements.txt")

    if not os.path.isfile(requirements_file):
        print(f"ERROR: Requirements file not found: {requirements_file}", file=sys.stderr)
        sys.exit(1)

    pip_cmd = [
        sys.executable,
        "-m",
        "pip",
        "install",
        "--upgrade",
        "-r",
        requirements_file,
    ]

    extra_args = os.environ.get("PIP_EXTRA_ARGS", "").split()
    if extra_args:
        pip_cmd.extend(extra_args)

    run(pip_cmd)


if __name__ == "__main__":
    main()